  to: phoneTo,
  type: "text",
  text: {
    body: messageText,
    preview_url: true
  }
};

parameters.query:
INSERT INTO message_buffer (phone, phone_to, message_body, customer_name, wamid, waba_id, timestamp_msg, dentro_horario, batch_id, created_at)
VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9, NOW())
ON CONFLICT DO NOTHING;

parameters.jsCode:
const from = $('Parsear Mensaje').item.json.from;
const batchId = `${from}_${Date.now()}`;

return {
  ...$('Parsear Mensaje').item.json,
  batchId
};

const mensajes = $input.all().map(i => i.json);
const miBatchId = $('Generar Batch ID').item.json.batchId;

if (mensajes.length === 0) {
  return { continuar: false, mensajeCombinado: '' };
}

const ultimoMensaje = mensajes[mensajes.length - 1];
const soyElUltimo = ultimoMensaje.batch_id === miBatchId;

if (!soyElUltimo) {
  return { continuar: false, mensajeCombinado: '' };
}

const mensajeCombinado = mensajes
  .map(m => m.message_body)
  .filter(Boolean)
  .join('\n');

const ids = mensajes.map(m => m.id);

return {
  continuar: true,
  mensajeCombinado,
  bufferIds: ids,
  from: mensajes[0].phone,
  to: mensajes[0].phone_to,
  customerName: mensajes[0].customer_name,
  wamid: ultimoMensaje.wamid,
  wabaId: ultimoMensaje.waba_id,
  timestamp: ultimoMensaje.timestamp_msg,
  dentroDeHorario: ultimoMensaje.dentro_horario
};

const data = $('Verificar y Concatenar').item.json;

return {
  from: data.from,
  to: data.to,
  customerName: data.customerName,
  messageBody: data.mensajeCombinado,
  wamid: data.wamid,
  wabaId: data.wabaId,
  timestamp: data.timestamp,
  dentroDeHorario: data.dentroDeHorario
};

parameters.query:
UPDATE message_buffer
SET processed = true
WHERE id = ANY(string_to_array($1, ',')::int[]);

options.queryReplacement:
={{
  (Array.isArray($('Verificar y Concatenar').first().json.bufferIds)
    ? $('Verificar y Concatenar').first().json.bufferIds
    : [ $('Verificar y Concatenar').first().json.bufferIds ]
  )
  .map((x) => Number(x))
  .filter((x) => Number.isFinite(x))
  .join(',')
}}

